INSERT INTO `papeteries` VALUES (20014,'uploads/agenda-famille.jpg','AG 2024 Agenda Famille FR week wire-o','Brepols agenda | FR','&lt;p&gt;Brepols agenda de la famille FR wire- o bilingue pour faire le planning pour 6 membres de la famille en une fois. 1 semaine par 2 pages clair et pratique avec les vacances scolaires sur format 16,5 x 21,5 cm.&lt;/p&gt;',13.80,1,2),(20037,'uploads/bloc-papier.jpg','Aurora bloc papier millimetré A4 bleu 50fls','Aurora','&lt;p&gt;Bloc de papier millim&amp;eacute;tr&amp;eacute; Aurora - A4 - papier de couleur bleu - 90g - 50 feuilles&lt;/p&gt;',8.20,0,2),(20038,'uploads/bullet-journal-2.jpg','Mijn Bullet Journal','Livre relié | Néerlandais','&lt;p&gt;De basis voor een bullet journal is een leeg notitieboek met dotted papier. Een bullet journal heeft een vaste basis die je daarna verder kunt personaliseren. Sommige mensen stoppen ontzettend veel tijd in het personaliseren van hun bullet journal en versieren hem met handletters, doodles, ingewikkelde diagrammen en tekeningen... dat kan, maar hoeft natuurlijk niet. Hoe meer je met je journal doet, hoe bedrevener je erin wordt.&lt;br&gt;&lt;br&gt;Voor wie is een bullet journal?&lt;br&gt;&lt;br&gt;-Voor mensen die overal lijstjes rond laten slingeren.&lt;br&gt;-Voor mensen die van pen en papier houden.&lt;br&gt;-Voor mensen die doelen stellen en hun voortgang bijhouden.&lt;br&gt;-Voor mensen die gewoonten bijhouden in een logboek.&lt;br&gt;-Voor mensen met een plan.&lt;br&gt;-Voor iedereen die een plan zou willen hebben of meer orde in hun leven willen.&lt;br&gt;-Voor iedereen die een dagboek of agenda bij zou willen houden.&lt;/p&gt;',17.99,0,2),(20039,'uploads/bullet-journal.jpg','Mijn Bullet Journal','Livre broché | Néerlandais','&lt;p&gt;De basis voor een bullet journal is een leeg notitieboek met dotted papier. Een bullet journal heeft een vaste basis die je daarna verder kunt personaliseren. Sommige mensen stoppen ontzettend veel tijd in het personaliseren van hun bullet journal en versieren hem met handletters, doodles, ingewikkelde diagrammen en tekeningen... dat kan, maar hoeft natuurlijk niet. Hoe meer je met je journal doet, hoe bedrevener je erin wordt.&lt;br&gt;&lt;br&gt;Voor wie is een bullet journal?&lt;br&gt;&lt;br&gt;-Voor mensen die overal lijstjes rond laten slingeren.&lt;br&gt;-Voor mensen die van pen en papier houden.&lt;br&gt;-Voor mensen die doelen stellen en hun voortgang bijhouden.&lt;br&gt;-Voor mensen die gewoonten bijhouden in een logboek.&lt;br&gt;-Voor mensen met een plan.&lt;br&gt;-Voor iedereen die een plan zou willen hebben of meer orde in hun leven willen.&lt;br&gt;-Voor iedereen die een dagboek of agenda bij zou willen houden.&lt;/p&gt;',17.99,0,2),(20040,'uploads/crayons-couleurs.jpg','Bic Tropicolors crayons couleurs x18','BIC kids','&lt;p&gt;Crayon de couleur super r&amp;eacute;sistant sans bois Id&amp;eacute;al pour les dessins et coloriages d&amp;eacute;taill&amp;eacute;s sur de grandes surfaces pour les enfants de 5+ Mine r&amp;eacute;sistante Facile &amp;agrave; tailler Mine de 3,2 mm, &amp;agrave; base de pigments, pour un excellent pouvoir couvrant&lt;/p&gt;',6.20,1,2),(20041,'uploads/paint-on-bloc.jpg','Paint\'ON bloc multi-technique de dessin','Clairefontaine','&lt;p&gt;Papier extra blanc 100% cellulose au grain tr&amp;egrave;s l&amp;eacute;ger. C&#039;est un parfait multi-technique. Il s&#039;adapte &amp;agrave; la fois aux techniques s&amp;egrave;ches (crayon, le stylo graph ou feutres) et aux techniques humides telles que l&#039;encre de Chine, la gouache et l&#039;acrylique gr&amp;acirc;ce &amp;agrave; sa bonne capacit&amp;eacute; d&#039;absorption. De par son grain tr&amp;egrave;s l&amp;eacute;ger, il s&#039;accordera le mieux aux travaux de d&amp;eacute;tails.&lt;/p&gt;',12.20,1,2),(20042,'uploads/stabilo-crayons.jpg','Stabilo crayons de couleurs','STABILOaquacolor','&lt;p&gt;STABILOaquacolor&amp;reg; ARTY &amp;eacute;tui carton 24 pcs. STABILOaquacolor est un crayon de couleur enti&amp;egrave;rement aquarellable de haute qualit&amp;eacute;.Issu du savoir-faire beaux-arts de STABILO, il r&amp;eacute;pond parfaitement aux besoins des sp&amp;eacute;cialistes de la couleur. Disponible en 36 couleurs vives et intenses.Excellente miscibilit&amp;eacute; &amp;agrave; sec et en technique de d&amp;eacute;trempe.&lt;/p&gt;',20.40,1,2),(20043,'uploads/paperstore-grand.jpg','Paperstore grand carnet à spirale','PaperStore','&lt;p&gt;Dit trendy notitieboek met spiraalbinding is voorzien van een stevige, flexibele kaft en kwaliteitsvol papier om doordrukken te voorkomen. Ideaal om al je notities, idee&amp;euml;n en gedachten in op te schrijven en te bewaren. Gelinieerde pagina&#039;s.&lt;br&gt;Ce carnet de notes styl&amp;eacute; &amp;agrave; spirale est pourvu d&#039;une couverture solide et souple. Le papier de qualit&amp;eacute; emp&amp;ecirc;che les &amp;eacute;crits de traverser les feuilles. Id&amp;eacute;al pour y consigner vos notes, id&amp;eacute;es et pens&amp;eacute;es. Pages lign&amp;eacute;es.&lt;/p&gt;',12.95,1,2),(20044,'uploads/toy-story.jpg','Disney Vriendenboek Toy Story 4','Livre relié | Néerlandais','&lt;p&gt;In dit leuke vriendenboek kun je al je vrienden en vriendinnen een heleboel weetjes over zichzelf laten vertellen: waar ze wonen, wanneer ze jarig zijn, wat ze het liefst eten, welke hobby&#039;s ze hebben en nog veel meer. Bovendien kunnen ze de kleurplaat met stiften of kleurpotloden omtoveren tot een pareltje en een mooie foto van zichzelf toevoegen! Zo wordt dit boek een kostbare herinnering voor later aan al je vriendjes en klasgenootjes. Gebonden uitvoering.&lt;/p&gt;',14.95,1,2),(20045,'uploads/vriendenboek.jpg','Vriendenboek','Livre relié | Néerlandais','&lt;p&gt;Een splinternieuw vriendenboek voor jongens en meisjes!&lt;br&gt;Om in te kleuren, te schrijven en te tekenen. Met vragen en opdrachten en ruimte voor een gedicht of een kunstwerk.&lt;br&gt;Geef het aan al je vrienden, maar ook aan je familie, je lievelingstante, je buurman en je opa!&lt;br&gt;Mooi gebonden en gedrukt op stevig papier.&lt;br&gt;Maak er iets moois van en bewaar het goed!&lt;/p&gt;',13.90,1,2),(20046,'uploads/noris-colour-crayons.jpg','Staedtler noris colour crayons','Staedtler','&lt;p&gt;Noris colour 185 crayon de couleur. Le premier crayon de couleur fait du mat&amp;eacute;riau WOPEX. Forme hexagonale. Grande r&amp;eacute;sistance au bris. Surface ergonomique douce. Le mat&amp;eacute;riau bois est issu de for&amp;ecirc;ts allemandes certifi&amp;eacute;es PEFC. Etui carton compos&amp;eacute; de 24 couleurs assorties 20 + 4 gratis&lt;/p&gt;',7.90,1,2),(20047,'uploads/dessin-steinbach.jpg','Aurora bloc dessin steinbach','Aurora','&lt;p&gt;Bloc de dessin Aurora - A4 - papier blanc steinbach - 250g - 20 feuilles&lt;/p&gt;',9.60,1,2),(20048,'uploads/dessin-grain.jpg','Clairefontaine bloc dessin grain','Clairefontaine','&lt;p&gt;Papier &amp;agrave; dessin en bloc de 20 feuilles, 224g, A4 (21x29,7cm). Papier &amp;agrave; dessin &amp;agrave; grain fin. Bloc coll&amp;eacute; en t&amp;ecirc;te.&lt;/p&gt;',12.00,1,2),(20049,'uploads/power-feutres.jpg','Stabilo power feutres maxi','Stabilo','&lt;p&gt;Etui de 12 feutres pointe large STABILO POWER MAX, couleurs assorties&lt;br&gt;- Peut rester ouvert 8 semaines sans s&amp;eacute;cher!&lt;br&gt;- Pointe bloqu&amp;eacute;e r&amp;eacute;sistante &amp;agrave; la pression&lt;br&gt;- Encre &amp;agrave; base d&#039;eau, lavable&lt;br&gt;- Capuchon ventil&amp;eacute;&lt;br&gt;- Pointe large de 3,0 mm&lt;/p&gt;',13.10,1,2),(20050,'uploads/maped-crayons.jpg','Crayons de couleur infinity en boite carton','Maped Color\'Peps','&lt;p&gt;Maped crayons de couleur infinity en boite carton x12 FR&lt;/p&gt;',5.40,1,2),(20051,'uploads/wow-fashion-book.jpg','Fashion Book crée ton style ass','Wow Generation','&lt;p&gt;Dimensions :240 mm x 45 mm x 314 mm&lt;/p&gt;',28.90,1,2),(20052,'uploads/cahier-pique.jpg','Clairenfantine cahier piqué A5','Clairefontaine','&lt;p&gt;PIQURE 17X22 64P DL3MMI + MARGE PEFC90G&lt;/p&gt;',3.70,1,2),(20053,'uploads/cahier-ligne.jpg','Cahier A5 ligné polypropylène transparent','Atoma','&lt;p&gt;Les r&amp;eacute;pertoires Atoma offrent un syst&amp;egrave;me de prise de notes, de classement et de reliure unique et personnalisable, avec tous les avantages des cahiers &amp;agrave; spirale et des reliures &amp;agrave; anneaux, et aucun des inconv&amp;eacute;nients. La gamme Atoma Transparent offre des couvertures de diff&amp;eacute;rente couleurs avec 6 intercalaires et 5 plastiques. De plus, les pages Atoma sont de haute qualit&amp;eacute; (90gr/m&amp;sup2;) pour le plaisir d&#039;&amp;eacute;crire. Il sera &amp;eacute;galement facile d&#039;ajouter des feuilles suppl&amp;eacute;mentaires gr&amp;acirc;ce aux recharges Atoma. Ainsi, vous n&#039;aurez plus de probl&amp;egrave;mes pour &amp;eacute;crire toutes vos notes &amp;agrave; un m&amp;ecirc;me endroit.&lt;/p&gt;',8.20,1,2),(20054,'uploads/carnet-spirale.jpg','Carnet A5 spirale 148p ligné','Clairefontaine','&lt;p&gt;Terracotta, Carnet reliure int&amp;eacute;grale A5 148p lign&amp;eacute;&lt;/p&gt;',6.95,1,2),(20055,'uploads/chemises-plastiques.jpg','Atoma chemises plastiques','Atoma','&lt;p&gt;Les chemises plastiques pour les fardes Atoma sont id&amp;eacute;ales pour rajouter vos documents, vos pr&amp;eacute;sentations ou vos offres et de les prot&amp;eacute;ger. Ce produit Atoma est pratique,vous pourrez facilement garder vos documents bien organis&amp;eacute;s.&lt;/p&gt;',3.20,1,2),(20056,'uploads/repertoire-pique.jpg','Clairefontaine répertoire piqué A7','Clairefontaine','&lt;p&gt;REPERTOIRE PIQUE 90X140 96P 5X5 90G&lt;/p&gt;',6.00,1,2),(20057,'uploads/pritt-correcteur.jpg','Correcteur mini roller color','Pritt','&lt;p&gt;Gr&amp;acirc;ce au bo&amp;icirc;tier tr&amp;egrave;s compact du Mini Roller de Correction de Pritt, ce produit est id&amp;eacute;al dans une trousse et &amp;agrave; emporter. Utilisez le Correction Mini Roller pour corriger du texte tap&amp;eacute; &amp;agrave; la machine et du texte &amp;eacute;crit en petit.&lt;/p&gt;',7.00,1,2),(20058,'uploads/chromaline-classeur.jpg','Exacompta Chromaline classeur','Exacompta','&lt;p&gt;Classeur 2 anneaux 20 mm polypropyl&amp;egrave;ne Chromaline - A4 Un polypropyl&amp;egrave;ne souple et transparent qui s&#039;adapte &amp;agrave; tout type de classement. Format A4, adapt&amp;eacute; au classement de feuilles, pochettes perfor&amp;eacute;es et intercalaires A4.&lt;/p&gt;',2.90,1,2),(20059,'uploads/post-it.jpg','Index assortiment de couleurs','Post-it','&lt;p&gt;Que ce soit pour un &amp;eacute;tudiant annotant son syllabus, un amoureux des livres d&amp;eacute;sirant retenir une page ou bien vous, qui avez simplement besoin de mettre des signets dans un dossier, ces Post-it Index sont faits sp&amp;eacute;cialement pour &amp;ccedil;a! Disponible en mauve, bleu, vert, rouge, rose ou jaune, ils mettront de la couleur dans vos papiers.&lt;/p&gt;',5.90,1,2);
